INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  14,
  11,
  2,
  'Which summary best fits 2 Chronicles 11?',
  '["Solomon arranges for cedar, skilled labor, and abundant materials so the temple can be built with excellence. He writes to Hiram and explains that the house will be for the great God whose name fills heaven and earth. The chapter shows deliberate preparation before construction begins.","Solomon begins construction of the temple on Mount Moriah, the place associated with Abraham''s sacrifice. The chapter carefully describes the dimensions, materials, and ornamentation of the house. The emphasis falls on holiness, continuity, and the visible beauty of worship.","Rehoboam plans to fight the breakaway tribes, but God forbids the civil war and preserves the division. Judah is strengthened with fortified cities, and priests and Levites from the north come south to support the true temple. The chapter shows that God still cares for David''s line even after the rupture.","Solomon offers sacrifice at Gibeon and asks God for wisdom rather than riches or long life. God grants him wisdom, knowledge, wealth, and honor beyond any king before or after him. The chapter establishes that Solomon''s greatness begins with dependence on God, not self-sufficiency."]'::jsonb,
  'Rehoboam plans to fight the breakaway tribes, but God forbids the civil war and preserves the division. Judah is strengthened with fortified cities, and priests and Levites from the north come south to support the true temple. The chapter shows that God still cares for David''s line even after the rupture.',
  'Rehoboam plans to fight the breakaway tribes, but God forbids the civil war and preserves the division. Judah is strengthened with fortified cities, and priests and Levites from the north come south to support the true temple. The chapter shows that God still cares for David''s line even after the rupture. (2 Chronicles 11:4)'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 14
    AND chapter = 11
    AND difficulty_stage = 2
    AND prompt = 'Which summary best fits 2 Chronicles 11?'
);

