INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  14,
  18,
  2,
  'Which summary best fits 2 Chronicles 18?',
  '["Solomon offers sacrifice at Gibeon and asks God for wisdom rather than riches or long life. God grants him wisdom, knowledge, wealth, and honor beyond any king before or after him. The chapter establishes that Solomon''s greatness begins with dependence on God, not self-sufficiency.","Solomon arranges for cedar, skilled labor, and abundant materials so the temple can be built with excellence. He writes to Hiram and explains that the house will be for the great God whose name fills heaven and earth. The chapter shows deliberate preparation before construction begins.","Solomon begins construction of the temple on Mount Moriah, the place associated with Abraham''s sacrifice. The chapter carefully describes the dimensions, materials, and ornamentation of the house. The emphasis falls on holiness, continuity, and the visible beauty of worship.","Jehoshaphat forms an alliance with Ahab, but Micaiah alone speaks the true word that the battle will end in disaster. The false prophets promise victory, yet Ahab''s attempt to disguise himself cannot avoid the judgment announced. The chapter warns against compromising alliances even when the language of religion sounds confident."]'::jsonb,
  'Jehoshaphat forms an alliance with Ahab, but Micaiah alone speaks the true word that the battle will end in disaster. The false prophets promise victory, yet Ahab''s attempt to disguise himself cannot avoid the judgment announced. The chapter warns against compromising alliances even when the language of religion sounds confident.',
  'Jehoshaphat forms an alliance with Ahab, but Micaiah alone speaks the true word that the battle will end in disaster. The false prophets promise victory, yet Ahab''s attempt to disguise himself cannot avoid the judgment announced. The chapter warns against compromising alliances even when the language of religion sounds confident. (2 Chronicles 18:3)'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 14
    AND chapter = 18
    AND difficulty_stage = 2
    AND prompt = 'Which summary best fits 2 Chronicles 18?'
);

