INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  14,
  32,
  2,
  'Which summary best fits 2 Chronicles 32?',
  '["Solomon begins construction of the temple on Mount Moriah, the place associated with Abraham''s sacrifice. The chapter carefully describes the dimensions, materials, and ornamentation of the house. The emphasis falls on holiness, continuity, and the visible beauty of worship.","Sennacherib threatens Judah, but Hezekiah strengthens the city and seeks the LORD, who sends deliverance from the Assyrian army. Later Hezekiah becomes proud over the riches God gave him, and the chapter records both his faith and his failing. The mix of rescue and pride keeps the reform story realistic.","Solomon offers sacrifice at Gibeon and asks God for wisdom rather than riches or long life. God grants him wisdom, knowledge, wealth, and honor beyond any king before or after him. The chapter establishes that Solomon''s greatness begins with dependence on God, not self-sufficiency.","Solomon arranges for cedar, skilled labor, and abundant materials so the temple can be built with excellence. He writes to Hiram and explains that the house will be for the great God whose name fills heaven and earth. The chapter shows deliberate preparation before construction begins."]'::jsonb,
  'Sennacherib threatens Judah, but Hezekiah strengthens the city and seeks the LORD, who sends deliverance from the Assyrian army. Later Hezekiah becomes proud over the riches God gave him, and the chapter records both his faith and his failing. The mix of rescue and pride keeps the reform story realistic.',
  'Sennacherib threatens Judah, but Hezekiah strengthens the city and seeks the LORD, who sends deliverance from the Assyrian army. Later Hezekiah becomes proud over the riches God gave him, and the chapter records both his faith and his failing. The mix of rescue and pride keeps the reform story realistic. (2 Chronicles 32:7)'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 14
    AND chapter = 32
    AND difficulty_stage = 2
    AND prompt = 'Which summary best fits 2 Chronicles 32?'
);

