INSERT INTO quiz_question_bank (book_number, chapter, difficulty_stage, prompt, choices_json, correct_answer, explanation)
SELECT
  14,
  36,
  2,
  'Which summary best fits 2 Chronicles 36?',
  '["Solomon begins construction of the temple on Mount Moriah, the place associated with Abraham''s sacrifice. The chapter carefully describes the dimensions, materials, and ornamentation of the house. The emphasis falls on holiness, continuity, and the visible beauty of worship.","The final kings of Judah rebel, ignore the prophets, and lead the nation into exile as Jerusalem falls to Babylon. The temple is burned, the people are carried away, and the land rests until a new decree from Cyrus opens the door for return. The book ends in judgment but also with the first note of restoration.","Solomon offers sacrifice at Gibeon and asks God for wisdom rather than riches or long life. God grants him wisdom, knowledge, wealth, and honor beyond any king before or after him. The chapter establishes that Solomon''s greatness begins with dependence on God, not self-sufficiency.","Solomon arranges for cedar, skilled labor, and abundant materials so the temple can be built with excellence. He writes to Hiram and explains that the house will be for the great God whose name fills heaven and earth. The chapter shows deliberate preparation before construction begins."]'::jsonb,
  'The final kings of Judah rebel, ignore the prophets, and lead the nation into exile as Jerusalem falls to Babylon. The temple is burned, the people are carried away, and the land rests until a new decree from Cyrus opens the door for return. The book ends in judgment but also with the first note of restoration.',
  'The final kings of Judah rebel, ignore the prophets, and lead the nation into exile as Jerusalem falls to Babylon. The temple is burned, the people are carried away, and the land rests until a new decree from Cyrus opens the door for return. The book ends in judgment but also with the first note of restoration. (2 Chronicles 36:5)'
WHERE NOT EXISTS (
  SELECT 1 FROM quiz_question_bank
  WHERE book_number = 14
    AND chapter = 36
    AND difficulty_stage = 2
    AND prompt = 'Which summary best fits 2 Chronicles 36?'
);

